// Generate daily summary stats
const allLeads = $input.all();
const now = new Date();
const todayStart = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Dubai' }));
todayStart.setHours(0, 0, 0, 0);

let todayLeads = 0;
let totalLeads = allLeads.length;
let newLeads = 0;
let contactedLeads = 0;
let convertedLeads = 0;
let inquiries = 0;
let orders = 0;
let complaints = 0;
let arabicLeads = 0;
let englishLeads = 0;

for (const item of allLeads) {
  const lead = item.json;
  const leadDate = new Date(lead.timestamp);

  if (leadDate >= todayStart) {
    todayLeads++;
  }

  // Status counts
  if (lead.status === 'new') newLeads++;
  if (lead.status === 'contacted') contactedLeads++;
  if (lead.status === 'converted') convertedLeads++;

  // Type counts
  if (lead.type === 'inquiry') inquiries++;
  if (lead.type === 'order') orders++;
  if (lead.type === 'complaint') complaints++;

  // Language counts
  if (lead.language === 'ar') arabicLeads++;
  if (lead.language === 'en') englishLeads++;
}

const summary = `📊 *Daily AI Receptionist Report*\n` +
  `📅 ${now.toLocaleDateString('en-US', { timeZone: 'Asia/Dubai', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}\n\n` +
  `*Today's Activity:*\n` +
  `• New leads today: ${todayLeads}\n` +
  `• Total leads all-time: ${totalLeads}\n\n` +
  `*Lead Status:*\n` +
  `• 🆕 New (awaiting contact): ${newLeads}\n` +
  `• 📞 Contacted: ${contactedLeads}\n` +
  `• ✅ Converted: ${convertedLeads}\n\n` +
  `*Inquiry Types:*\n` +
  `• 💬 General inquiries: ${inquiries}\n` +
  `• 🛒 Orders: ${orders}\n` +
  `• ⚠️ Complaints: ${complaints}\n\n` +
  `*Languages:*\n` +
  `• 🇬🇧 English: ${englishLeads}\n` +
  `• 🇦🇪 Arabic: ${arabicLeads}\n\n` +
  `_Report generated automatically by AI Receptionist_`;

return [{ json: { summary, todayLeads, totalLeads } }];
